sql:
SELECT d.carat, c.cut_name
FROM diamonds d
JOIN cuts c ON d.cut_id = c.cut_id;

SELECT COUNT(*)
FROM diamonds
WHERE sale_price > 5000 AND status = 'sold';

SELECT COUNT(*) AS number_of_diamonds
FROM diamonds
WHERE cut_id = (SELECT cut_id FROM cuts WHERE cut_name = 'Ideal');

SELECT AVG(d.purchase_price) AS average_purchase_price
FROM diamonds d
WHERE d.evaluation_date > '2022-01-01' AND d.status = 'in inventory';

external_knowledge:
- 'crown jewels' refers to the top 5 most valuable diamonds based on their sale price; 
- 'master craftsman' refers to the user who last modified the diamond record;
- 'polished' refers to the last modification made to the diamond record.

sql:
SELECT COUNT(diamond_id) AS num_diamonds
FROM diamonds
WHERE color_id = (SELECT color_id FROM colors WHERE color_name = 'D');
